        @mcp.tool()
        async def zip_update_entry(
            input_filename: str,
            entry_name: str,
            new_file_filename: str,
        ) -> dict:
            """
            Replace an existing entry in a ZIP archive with a new file.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the ZIP archive.
                entry_name: Name of the entry to replace.
                new_file_filename: Bare filename of the new file to substitute.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str
                }
        
            Raises:
                FileNotFoundError: If the ZIP archive or the new file does not exist.
                KeyError: If the specified entry_name is not found in the archive.
                Exception: Any unexpected error from the Aspose.Zip library.
        
            Example:
                result = await zip_update_entry(
                    input_filename="documents.zip",
                    entry_name="old_report.pdf",
                    new_file_filename="new_report.pdf",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input files (must be done before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            # sanitize and resolve the ZIP archive filename
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # sanitize and resolve the new file to be inserted
            new_file_filename = Path(new_file_filename.strip().replace('\x00', '')).name
            resolved_new_file = get_safe_path(new_file_filename)
            if not Path(resolved_new_file).is_file():
                raise FileNotFoundError(f"File not found: {new_file_filename}")
        
            # ----------------------------------------------------------------------
            # Aspose.Zip processing
            # ----------------------------------------------------------------------
            import logging
            import aspose.zip as az
        
            logger = logging.getLogger(__name__)
        
            try:
                with az.Archive(str(resolved_input)) as archive:
                    # locate the entry to replace
                    entry = next((e for e in archive.entries if e.name == entry_name), None)
                    if entry is None:
                        raise KeyError(f"Entry '{entry_name}' not found")
        
                    # delete the old entry and add the new one
                    archive.delete_entry(entry)
                    archive.create_entry(entry_name, str(resolved_new_file))
        
                    # save changes back to the same archive file
                    archive.save(str(resolved_input))
        
                logger.info(
                    "Replaced entry '%s' in archive '%s' with file '%s'.",
                    entry_name,
                    input_filename,
                    new_file_filename,
                )
                return {"status": "success", "message": f"Entry '{entry_name}' updated successfully."}
            except Exception as exc:  # pragma: no cover
                logger.error(
                    "Failed to update entry '%s' in archive '%s': %s",
                    entry_name,
                    input_filename,
                    str(exc),
                )
                return {"status": "error", "message": str(exc)}

